# %% ../nbs/12_tools.ipynb #c8fe2955
def insert_line(
    text:str,
    insert_line:int, # The 1-based line number after which to insert the text (0: before 1st line, 1: after 1st line, 2: after 2nd, etc.)
    new_str:str, # The text to insert
):
    "Insert new_str at specified line number"
    lines = text.splitlines()
    if not (0 <= insert_line <= len(lines)): raise ValueError(f'Invalid line {insert_line}. Valid range: 0-{len(lines)}')
    lines.insert(insert_line, new_str)
    return '\n'.join(lines)

# %% ../nbs/12_tools.ipynb #dc8ed4b7
def _norm_lines(n:int, start:int=None, end:int=None):
    "Normalize and validate line range; `None` start/end mean first/last line. Returns (start, end) or raises ValueError."
    if start is None: start = 1
    if end is None: end = n
    if end < 0: end = n + end + 1
    if not (1 <= start <= n): raise ValueError(f'Invalid start line {start}. Valid range: 1-{n}')
    if not (start <= end <= n): raise ValueError(f'Invalid end line {end}. Valid range: {start}-{n}')
    return start, end

# %% ../nbs/12_tools.ipynb #c2764d2a
def str_replace(
    text:str,
    old_str:str, # Text to find and replace
    new_str:str, # Text to replace with
    start_line:int=None, # Optional 1-based start line to limit search
    end_line:int=None, # Optional 1-based end line to limit search
    n_matches:int=None, # Max replacements (None=all)
    re_filter:str=None, # If provided, only process lines matching this regex (like g// in ex)
    invert_filter:bool=False, # Invert the filter (like g!// in ex)
    use_regex:bool=False, # Treat old_str as a regex, and new_str as an `re.sub` template?
):
    "Replace occurrence(s) of old_str with new_str"
    pat = re.compile(old_str) if use_regex else None
    def _repl(s, label=''):
        def _err(s): return ValueError(f"Failed to find {old_str!r}{label} in: {s[:200]!r}" + ('...' if len(s)>200 else ''))
        if pat:
            if not pat.search(s): raise _err(s)
            return pat.sub(new_str, s, count=n_matches or 0)
        if s.count(old_str) == 0: raise _err(s)
        return s.replace(old_str, new_str) if n_matches is None else s.replace(old_str, new_str, n_matches)
    if re_filter or start_line is not None or end_line is not None:
        lines = text.splitlines(True)
        s,e = _norm_lines(len(lines), start_line, end_line)
        s -= 1
        if not re_filter: return ''.join(lines[:s]) + _repl(''.join(lines[s:e]), f' in lines {s+1}-{e}') + ''.join(lines[e:])
        pat = re.compile(re_filter)
        matched = [i for i in range(s,e) if bool(pat.search(lines[i])) != invert_filter]
        if not matched: return text
        for i in matched: lines[i] = _repl(lines[i], f' on line {i+1}')
        return ''.join(lines)
    return _repl(text)

# %% ../nbs/12_tools.ipynb #e9c8cbcc
def strs_replace(
    text:str,
    old_strs:list[str], # List of strings to find and replace
    new_strs:list[str], # List of replacement strings (must match length of old_strs)
    start_line:int=None, # Optional 1-based start line to limit search
    end_line:int=None, # Optional 1-based end line to limit search
    n_matches:int=None, # Max replacements per string (None=all)
    re_filter:str=None, # If provided, only process lines matching this regex (like g// in ex)
    invert_filter:bool=False, # Invert the filter (like g!// in ex)
    use_regex:bool=False, # Treat old_strs as regexes, and new_strs as `re.sub` templates?
):
    "Replace multiple strings simultaneously"
    if not isinstance(old_strs, list): raise ValueError(f"`old_strs` should be a list[str] but got {type(old_strs)}")
    if not isinstance(new_strs, list): raise ValueError(f"`new_strs` should be a list[str] but got {type(new_strs)}")
    if len(old_strs) != len(new_strs): raise ValueError(f"Length mismatch: {len(old_strs)} old_strs vs {len(new_strs)} new_strs")
    for idx,(old_str,new_str) in enumerate(zip(old_strs, new_strs)):
        text = str_replace(text, old_str, new_str, start_line=start_line, end_line=end_line,
            n_matches=n_matches, re_filter=re_filter, invert_filter=invert_filter, use_regex=use_regex)
    return text

# %% ../nbs/12_tools.ipynb #1f61226a
def replace_lines(
    text:str,
    start_line:int=None, # Starting line number to replace (1-based); None means line 1
    end_line:int=None, # Ending line number to replace (1-based, inclusive, negative counts from end); None means the last line
    new_content:str='', # New content to replace the specified lines
):
    "Replace line range with new content; the defaults replace the entire contents"
    if not text: return new_content
    lines = text.splitlines(keepends=True)
    s,e = _norm_lines(len(lines), start_line, end_line)
    if new_content and not new_content.endswith('\n'): new_content += '\n'
    lines[s-1:e] = [new_content] if new_content else []
    return ''.join(lines)

# %% ../nbs/12_tools.ipynb #33ba0d24
def del_lines(
    text:str,
    start_line:int, # Starting line number to delete (1-based); required
    end_line:int, # Ending line number to delete (1-based, inclusive, negative counts from end); required
    re_filter:str=None, # If provided, only delete lines matching this regex (like g// in ex)
    invert_filter:bool=False, # Invert the filter (like g!// in ex)
):
    "Delete line range; deletion is destructive, so both line numbers must be given explicitly (`1, -1` for all lines)"
    if start_line is None or end_line is None: raise ValueError('del_lines requires explicit start_line and end_line')
    lines = text.splitlines(keepends=True)
    s,e = _norm_lines(len(lines), start_line, end_line)
    if re_filter:
        pat = re.compile(re_filter)
        matched = {i for i in range(s-1,e) if bool(pat.search(lines[i])) != invert_filter}
        if not matched: return text
        lines = [l for i,l in enumerate(lines) if i not in matched]
    else: del lines[s-1:e]
    return ''.join(lines)

# %% ../nbs/12_tools.ipynb #6274581f
def line_hash(
    line:str # A single line of text, without trailing newline
)->str:
    "4-char hex exhash hash of `line`"
    return f'{zlib.crc32(line.encode()) & 0xffff:04x}'

def lnhash(
    lineno:int, # 1-based line number
    line:str # The line's current text
)->str:
    "`lineno|hash|` exhash address for `line` at `lineno`"
    return f'{lineno}|{line_hash(line)}|'

def lnhash_at(
    s:str|list|tuple, # A document as a str, or its lines
    line:int # 1-based line number within `s`
)->str:
    "`lineno|hash|` exhash address of line `line` of `s`"
    if isinstance(s,str): s = s.splitlines()
    return lnhash(line, s[line-1])

# %% ../nbs/12_tools.ipynb #806c957b
def view_file(
    path:str, # Path to view (expands `~` if needed)
    start_line:int=1, # Starting line to view
    end_line:int=None, # End line (defaults to last line if None; may be past EOF, which clamps to the last line - handy when the file size is unknown)
    lnhashs:bool=False # Prefix `lineno|hash|` exhash addresses instead of `lineno: `
):
    "Read file contents, optionally limited to 1-based line range"
    path = Path(path).expanduser()
    lines = path.read_text().splitlines()
    if not lines: return ''
    if end_line is None: end_line = len(lines)
    if end_line < 0: end_line = len(lines)+end_line+1
    if not (1 <= start_line <= len(lines)): return f'error: Invalid start_line {start_line}. Valid range: 1-{len(lines)}'
    if end_line > len(lines): end_line = len(lines)
    return PrettyString('\n'.join((lnhash(i,l) if lnhashs else f'{i}: ')+l for i,l in enumerate(lines[start_line-1:end_line], start_line)))

# %% ../nbs/12_tools.ipynb #424d09e1
def create_file(
    path:str, # Path to create (expands `~` if needed)
    contents:str, # Contents of file to create
    overwrite:bool=False, # Replace the file if it already exists?
):
    "Create a new file with contents. Error if file exists, unless `overwrite`."
    path = Path(path).expanduser()
    if path.exists() and not overwrite: return f'error: File exists: {path}'
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(contents)
    return 'done'

