def ast_replace(
    text:str,
    repls:list, # (pattern, replacement) ast-grep rules; replacement is a `$VAR` template or a callable(match)->str
):
    "Apply ast-grep structural pattern replacements to python source"
    try: from remold import astmap
    except ImportError as e: raise ImportError('ast_replace requires the optional `remold` package: `pip install remold`') from e
    return astmap(*repls)(text)

